body.script:
let array = [
  "https://images.pexels.com/photos/27219452/pexels-photo-27219452/free-photo-of-woman-in-white-dress-lying-down-on-couch.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=1",
  "https://images.pexels.com/photos/28857430/pexels-photo-28857430/free-photo-of-stack-of-delicious-homemade-cookies-on-plate.jpeg?auto=compress&cs=tinysrgb&w=600&lazy=load",
  "https://images.pexels.com/photos/29248997/pexels-photo-29248997/free-photo-of-contemplative-man-holding-a-large-clock-outdoors.jpeg?auto=compress&cs=tinysrgb&w=600&lazy=load",
  "./assets/images/player-image.png",
];

let image = document.getElementById("loadImage");
let currentIndex = 0;

function changeImage() {
  window.location.reload();

}

document.addEventListener("keydown", (event) => {
  // alert("space clicked");
  if (event.code === "Space") {
    event.preventDefault();
    changeImage();
  }
});

function setPlayerUnsold() {
  var modal = document.getElementById('unsoldConfirmModal');
  modal.style.display = 'flex';
}

(function() {
  document.addEventListener('DOMContentLoaded', function() {
    document.getElementById('unsoldModalCancel').addEventListener('click', function() {
      document.getElementById('unsoldConfirmModal').style.display = 'none';
    });
    document.getElementById('unsoldModalConfirm').addEventListener('click', function() {
      document.getElementById('unsoldConfirmModal').style.display = 'none';
      var playerId = parseInt(document.body.getAttribute('data-player-id'));
      if (!playerId) {
        showUnsoldToast('Error: Player ID not found', true);
        return;
      }
      fetch('/web/dataset/call_kw', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
          jsonrpc: '2.0',
          method: 'call',
          params: {
            model: 'auction.team.player',
            method: 'action_unsold',
            args: [[playerId]],
            kwargs: {}
          }
        })
      }).then(function(response) {
        return response.json();
      }).then(function(result) {
        if (result.error) {
          showUnsoldToast('Failed to mark player as unsold', true);
        } else {
          var secs = (result.result && result.result.display_seconds > 0) ? result.result.display_seconds : 5;
          showUnsoldStamp(secs, '#b71c1c', '#fff');
        }
      }).catch(function() {
        showUnsoldToast('Failed to mark player as unsold', true);
      });
    });
  });
})();

function showUnsoldToast(message, isError) {
  var toast = document.getElementById('unsoldToast');
  toast.textContent = message;
  toast.style.background = isError ? '#c0392b' : '#27ae60';
  toast.style.display = 'block';
  setTimeout(function() { toast.style.display = 'none'; }, 3500);
}

function showUnsoldStamp(displaySeconds, stampColor, stampText) {
  if (!document.getElementById('_unsoldStampCSS')) {
    var s = document.createElement('style');
    s.id = '_unsoldStampCSS';
    s.textContent = '@keyframes _unsoldDrop{0%{transform:rotate(-22deg) scale(2.4);opacity:0}100%{transform:rotate(-22deg) scale(1);opacity:.92}}@keyframes _unsoldFadeIn{from{opacity:0}to{opacity:1}}';
    document.head.appendChild(s);
  }
  var img = document.getElementById('loadImage');
  var r = img.getBoundingClientRect();
  var ov = document.createElement('div');
  ov.style.cssText = 'position:fixed;z-index:9500;top:'+r.top+'px;left:'+r.left+'px;width:'+r.width+'px;height:'+r.height+'px;background:rgba(0,0,0,0.48);display:flex;align-items:center;justify-content:center;animation:_unsoldFadeIn .35s ease;pointer-events:none;';
  var stamp = document.createElement('div');
  stamp.style.cssText = 'background:'+stampColor+';color:'+stampText+';font-size:clamp(1.8rem,5vw,3.2rem);font-weight:900;letter-spacing:6px;padding:8px 36px;border:5px solid rgba(255,255,255,0.85);border-radius:6px;box-shadow:0 0 0 3px '+stampColor+',0 8px 40px rgba(0,0,0,.5);opacity:0;animation:_unsoldDrop .5s cubic-bezier(.34,1.3,.64,1) .15s forwards;text-shadow:2px 3px 8px rgba(0,0,0,.4);';
  stamp.textContent = 'UNSOLD';
  var barWrap = document.createElement('div');
  barWrap.style.cssText = 'position:absolute;bottom:12px;left:16px;right:16px;';
  var barTrack = document.createElement('div');
  barTrack.style.cssText = 'background:rgba(255,255,255,0.25);border-radius:4px;height:6px;overflow:hidden;';
  var bar = document.createElement('div');
  bar.style.cssText = 'height:100%;width:100%;background:'+stampColor+';border-radius:4px;transition:width '+displaySeconds+'s linear;';
  barTrack.appendChild(bar);
  barWrap.appendChild(barTrack);
  ov.appendChild(stamp);
  ov.appendChild(barWrap);
  document.body.appendChild(ov);
  requestAnimationFrame(function() { requestAnimationFrame(function() { bar.style.width = '0%'; }); });
  setTimeout(function() { if (ov.parentNode) ov.parentNode.removeChild(ov); changeImage(); }, displaySeconds * 1000);
}

function openBidSummary() {
  document.getElementById('bidSummaryFrame').src = '/auction/show/team/balance';
  document.getElementById('bidSummaryDrawer').style.right = '0';
  document.getElementById('bidSummaryTabArrow').innerHTML = '→';
  document.getElementById('bidSummaryOverlay').style.display = 'block';
  document.body.style.overflow = 'hidden';
}
function closeBidSummary() {
  document.getElementById('bidSummaryDrawer').style.right = '-820px';
  document.getElementById('bidSummaryTabArrow').innerHTML = '←';
  document.getElementById('bidSummaryOverlay').style.display = 'none';
  document.body.style.overflow = '';
}
function toggleBidSummary() {
  var r = document.getElementById('bidSummaryDrawer').style.right;
  if (r === '0px' || r === '0') { closeBidSummary(); } else { openBidSummary(); }
}
